/* --- Ground state: printable characters and C0 controls --- */

static void handle_c0(Terminal *term, uint8_t byte) {
    ScreenBuffer *scr = term->active;
    switch (byte) {
    case 0x07: /* BEL */
        /* Could trigger bell callback — ignore for now */
        break;
    case 0x08: /* BS */
        screen_cursor_back(scr, 1);
        break;
    case 0x09: /* HT */
        screen_tab(scr);
        break;
    case 0x0A: /* LF */
    case 0x0B: /* VT */
    case 0x0C: /* FF */
        if (scr->cursor.row == scr->scroll_bottom) {
            Scrollback *sb = term->using_alt ? NULL : term->scrollback;
            screen_scroll_up(scr, sb, 1);
        } else {
            screen_cursor_down(scr, 1);
        }
        break;
    case 0x0D: /* CR */
        scr->cursor.col = 0;
        scr->cursor.wrap_pending = 0;
        break;
    case 0x0E: /* SO — shift out: activate G1 */
        term->charset_active = 1;
        break;
    case 0x0F: /* SI — shift in: activate G0 */
        term->charset_active = 0;
        break;
    }
}

